mapper.select:
select distinct fs.special_id, tt.topic_name, fs.color_type,fs.special_name,fs.trial_id, ts.name speciesName, ts.name_en
speciesNameEn, fs.status, fs.create_time,su.user_name createName
from fr_special fs
left join tb_topic tt on fs.topic_id = tt.topic_id
left join sys_user su on fs.create_by = su.user_id
left join tb_species ts on fs.species_id = ts.species_id
left join fr_special_member fsm on fs.special_id = fsm.special_id
and  fsm.del_flag = '0'
and ts.organization_id = #{organizationId}
where fs.del_flag = '0'
and  fs.organization_id = #{organizationId}

    and tt.topic_name like concat('%', #{topicName}, '%')


    and fs.special_name like concat('%', #{specialName}, '%')


    and fs.trial_id = #{trialId}


    and fsm.user_id = #{userId}


    and fs.species_id = #{speciesId}


    and fs.status = #{status}


    and fs.color_type = #{colorType}


    and su.user_name like concat('%', #{createName}, '%')



        AND date_format(fs.create_time,'%Y%m%d') >= date_format(#{createTimeParams.beginTime},'%Y%m%d')


        AND date_format(fs.create_time,'%Y%m%d') <= date_format(#{createTimeParams.endTime},'%Y%m%d')


order by fs.create_time desc

select  fs.special_id, tt.topic_name, fs.color_type,fs.special_name,fs.trial_id, ts.name speciesName, ts.name_en
speciesNameEn, fs.status, fs.create_time,su.user_name createName
from fr_special fs
left join tb_topic tt on fs.topic_id = tt.topic_id
left join sys_user su on fs.create_by = su.user_id
left join tb_species ts on fs.species_id = ts.species_id
and ts.organization_id = #{organizationId}
left join fr_special_member fsm on fs.special_id = fsm.special_id
and fsm.del_flag = '0'
where fs.del_flag = '0'
and fs.status not in ('0','2')
and fs.organization_id = #{organizationId}

    and tt.topic_name like concat('%', #{topicName}, '%')


    and fs.special_name like concat('%', #{specialName}, '%')


    and fsm.user_id = #{loginUserId}


    and fs.trial_id = #{trialId}


    and fs.species_id = #{speciesId}


    and fs.status = #{status}


    and fs.color_type = #{colorType}


    and su.user_name like concat('%', #{createName}, '%')



        AND date_format(fs.create_time,'%Y%m%d') >= date_format(#{createTimeParams.beginTime},'%Y%m%d')


        AND date_format(fs.create_time,'%Y%m%d') <= date_format(#{createTimeParams.endTime},'%Y%m%d')


order by fs.create_time desc
